\documentclass[11pt,a4paper]{article}
\usepackage[utf8]{inputenc}
\usepackage[T1]{fontenc}
\usepackage[margin=1.5cm]{geometry}
\usepackage[hidelinks]{hyperref}
\usepackage{enumitem}
\usepackage{titlesec}
\usepackage{xcolor}
\usepackage{tabularx}

\urlstyle{same}
\definecolor{primary}{HTML}{1B4F72}
\titleformat{\section}{\large\bfseries\color{primary}\uppercase}{}{0em}{}[\titlerule]
\titlespacing*{\section}{0pt}{12pt}{8pt}

\begin{document}
\pagestyle{empty}

% Encabezado
\begin{center}
  {\Huge \textbf{ {{escapeLaTeX basics.name}} }}\\
  \vspace{4pt}
  {\large \color{primary} {{escapeLaTeX basics.label}} }\\
  \vspace{6pt}
  {{basics.email}} | {{basics.phone}} | {{escapeLaTeX basics.location.city}} \\
  \vspace{4pt}
  {{#if basics.profiles}}
    {{#each basics.profiles}}
      \href{ {{url}} }{ \textbf{ {{network}} }/{{username}} } {{#unless @last}} \hspace{4pt} | \hspace{4pt} {{/unless}}
    {{/each}}
  {{/if}}
\end{center}

% Perfil Profesional
{{#if (notEmpty basics.summary)}}
\section*{Perfil Profesional}
\noindent {{escapeLaTeX basics.summary}}
{{/if}}

% Habilidades
{{#if (notEmpty skills)}}
\section*{Habilidades y Competencias}
\begin{itemize}[leftmargin=*, label={}, itemsep=1pt]
  {{#each skills}}
    \item \textbf{ {{escapeLaTeX name}} }: {{join keywords ", "}}
  {{/each}}
\end{itemize}
{{/if}}

% Experiencia
{{#if (notEmpty work)}}
\section*{Experiencia}
{{#each work}}
  \noindent
  \begin{tabularx}{\textwidth}{Xr}
    \textbf{ {{escapeLaTeX name}} } & {{formatDate startDate}} -- {{#if endDate}}{{formatDate endDate}}{{else}}Presente{{/if}} \\
    \textit{ {{escapeLaTeX position}} } & \\
  \end{tabularx}
  \vspace{-4pt}
  {{#if (notEmpty highlights)}}
  \begin{itemize}[noitemsep, topsep=2pt, leftmargin=1.5em]
    {{#each highlights}} \item {{escapeLaTeX this}} {{/each}}
  \end{itemize}
  {{/if}}
  \vspace{6pt}
{{/each}}
{{/if}}

% Proyectos (Mejorado para descripciones sin highlights)
{{#if (notEmpty projects)}}
\section*{Proyectos e Implementaciones}
{{#each projects}}
  \noindent
  \begin{tabularx}{\textwidth}{Xr}
    \textbf{ {{escapeLaTeX name}} } & {{formatDate startDate}} -- {{#if endDate}}{{formatDate endDate}}{{else}}Presente{{/if}} \\
  \end{tabularx}
  \vspace{2pt}
  {{#if description}}
    \noindent \raggedright {{escapeLaTeX description}} \\
  {{/if}}
  \vspace{6pt}
{{/each}}
{{/if}}

% Formación Académica
{{#if (notEmpty education)}}
\section*{Formación Académica}
{{#each education}}
  \noindent
  \begin{tabularx}{\textwidth}{Xr}
    \textbf{ {{escapeLaTeX institution}} } & {{formatDate startDate}} -- {{#if endDate}}{{formatDate endDate}}{{else}}Presente{{/if}} \\
    {{escapeLaTeX studyType}}{{#if area}} en {{escapeLaTeX area}}{{/if}} {{#if score}} | Promedio: {{score}} {{/if}} & \\
  \end{tabularx}
  \vspace{6pt}
{{/each}}
{{/if}}

% Información Final
\section*{Información Adicional}
\begin{itemize}[leftmargin=*, label={}, itemsep=2pt]
  {{#if (notEmpty languages)}} \item \textbf{Idiomas:} {{#each languages}} {{language}} ({{fluency}}) {{#unless @last}} | {{/unless}} {{/each}} {{/if}}
  {{#if (notEmpty certificates)}} 
    {{#each certificates}}
    \item \textbf{Certificaciones:} {{escapeLaTeX name}} --- {{issuer}} ({{formatDate date}})
    {{/each}}
  {{/if}}
\end{itemize}

\end{document}
